package com.cognizant.springlearn.service; import com.cognizant.springlearn.dao.EmployeeDao; import com.cognizant.springlearn.model.Employee; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import java.util.List; @Service public class EmployeeService { private final EmployeeDao employeeDao; public EmployeeService(EmployeeDao employeeDao){this.employeeDao=employeeDao;} public List<Employee> getAllEmployees(){return employeeDao.getAll();} @Transactional public Employee updateEmployee(int id, Employee employee){return employeeDao.update(id, employee);} @Transactional public void deleteEmployee(int id){employeeDao.delete(id);} }
